class Solution:
    def solve(self, nums: list[int]) -> int:
        if not nums:
            return 0
        elif len(nums) <= 2:
            return max(0, max(nums))
        else:
            dp = [0]*len(nums)
            dp[0] = max(0, nums[0])
            dp[1] = max(dp[0], nums[1])
            for i in range(2, len(nums)):
                dp[i] = max(dp[i-1], dp[i-2] + nums[i])
            return dp[-1]

