#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(vector<int>& nums) {
        if (nums.empty()) {
            return 0;
        } else if (nums.size() <= 2) {
            return *max_element(nums.begin(), nums.end());
        }
        int prev = max(0, nums[0]);
        int curr = max(prev, nums[1]);
        for (int i = 2; i < nums.size(); i++) {
            int temp = curr;
            curr = max(curr, prev + nums[i]);
            prev = temp;
        }
        return curr;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    int ans = sol.solve(nums);
    cout << ans << "\n";
    return 0;
}
